import logging
import os
import json
from azure.functions import TimerRequest
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.eventgrid.models import EventGridEvent
from azure.identity import DefaultAzureCredential

# Initialize clients using managed identity
credential = DefaultAzureCredential()

# Configuration from environment variables
storage_account_name = os.environ["STORAGE_ACCOUNT_NAME"]
cosmos_db_endpoint = os.environ["COSMOS_DB_ENDPOINT"]
cosmos_db_key = os.environ["COSMOS_DB_KEY"]
cosmos_db_database_name = os.environ["COSMOS_DB_DATABASE_NAME"]
cosmos_db_container_name = os.environ["COSMOS_DB_CONTAINER_NAME"]
event_grid_topic_endpoint = os.environ["EVENT_GRID_TOPIC_ENDPOINT"]

# Initialize services
blob_service_client = BlobServiceClient(
    account_url=f"https://{storage_account_name}.blob.core.windows.net",
    credential=credential
)
cosmos_client = CosmosClient(
    cosmos_db_endpoint,
    credential=credential
)
event_grid_client = EventGridPublisherClient(
    endpoint=event_grid_topic_endpoint,
    credential=credential
)

def main(mytimer: TimerRequest, context: str):
    try:
        # Get container reference
        container_client = blob_service_client.get_container_client("input-container")
        
        # List blobs
        blob_list = container_client.list_blobs()
        
        for blob in blob_list:
            # Process blob
            blob_client = container_client.get_blob_client(blob.name)
            data = blob_client.download_blob().readall()
            
            # Validate and process data
            if not data:
                continue
                
            try:
                processed_data = json.loads(data)
            except json.JSONDecodeError:
                logging.error(f"Invalid JSON in blob {blob.name}")
                continue
            
            # Write to Cosmos DB
            database = cosmos_client.get_database_client(cosmos_db_database_name)
            container = database.get_container_client(cosmos_db_container_name)
            
            container.upsert_item(processed_data)
            
            # Send notification via Event Grid
            event = EventGridEvent(
                event_type="BlobProcessed",
                subject=f"blob/{blob.name}",
                data=processed_data,
                data_version="1.0"
            )
            
            event_grid_client.send([event])
            
            # Delete processed blob
            blob_client.delete_blob()
            
    except Exception as e:
        logging.error(f"Error processing blobs: {str(e)}")
        raise